   169→// String returns a string representation of the Histogram.
   170→func (h *Histogram) String() string {
   171→	var sb strings.Builder
   172→	fmt.Fprintf(&sb, "{count:%d, sum:%g", h.Count, h.Sum)
   173→
   174→	var nBuckets []Bucket[uint64]
   175→	for it := h.NegativeBucketIterator(); it.Next(); {
   176→		bucket := it.At()
   177→		if bucket.Count != 0 {
   178→			nBuckets = append(nBuckets, it.At())
   179→		}
   180→	}
   181→	for i := len(nBuckets) - 1; i >= 0; i-- {
   182→		fmt.Fprintf(&sb, ", %s", nBuckets[i].String())
   183→	}
   184→
   185→	if h.ZeroCount != 0 {
   186→		fmt.Fprintf(&sb, ", %s", h.ZeroBucket().String())
   187→	}
   188→
   189→	for it := h.PositiveBucketIterator(); it.Next(); {
   190→		bucket := it.At()
   191→		if bucket.Count != 0 {
   192→			fmt.Fprintf(&sb, ", %s", bucket.String())
   193→		}
   194→	}
   195→
   196→	sb.WriteRune('}')
   197→	return sb.String()
   198→}
   199→
   200→// ZeroBucket returns the zero bucket. This method panics if the schema is for custom buckets.
   201→func (h *Histogram) ZeroBucket() Bucket[uint64] {
   202→	if h.UsesCustomBuckets() {
   203→		panic("histograms with custom buckets have no zero bucket")
   204→	}
   205→	return Bucket[uint64]{
   206→		Lower:          -h.ZeroThreshold,
   207→		Upper:          h.ZeroThreshold,
   208→		LowerInclusive: true,
   209→		UpperInclusive: true,
   210→		Count:          h.ZeroCount,
   211→	}
   212→}
   213→
   214→// PositiveBucketIterator returns a BucketIterator to iterate over all positive
   215→// buckets in ascending order (starting next to the zero bucket and going up).
   216→func (h *Histogram) PositiveBucketIterator() BucketIterator[uint64] {
   217→	it := newRegularBucketIterator(h.PositiveSpans, h.PositiveBuckets, h.Schema, true, h.CustomValues)
   218→	return &it
   219→}
   220→
   221→// NegativeBucketIterator returns a BucketIterator to iterate over all negative
   222→// buckets in descending order (starting next to the zero bucket and going down).
   223→func (h *Histogram) NegativeBucketIterator() BucketIterator[uint64] {
   224→	it := newRegularBucketIterator(h.NegativeSpans, h.NegativeBuckets, h.Schema, false, nil)
   225→	return &it
   226→}
   227→
   228→// CumulativeBucketIterator returns a BucketIterator to iterate over a
   229→// cumulative view of the buckets. This method currently only supports
   230→// Histograms without negative buckets and panics if the Histogram has negative
   231→// buckets. It is currently only used for testing.
   232→func (h *Histogram) CumulativeBucketIterator() BucketIterator[uint64] {
   233→	if len(h.NegativeBuckets) > 0 {
   234→		panic("CumulativeBucketIterator called on Histogram with negative buckets")
   235→	}
   236→	return &cumulativeBucketIterator{h: h, posSpansIdx: -1}
   237→}
   238→
   239→// Equals returns true if the given histogram matches exactly.
   240→// Exact match is when there are no new buckets (even empty) and no missing buckets,
   241→// and all the bucket values match. Spans can have different empty length spans in between,
   242→// but they must represent the same bucket layout to match.
   243→// Sum is compared based on its bit pattern because this method
   244→// is about data equality rather than mathematical equality.
   245→// We ignore fields that are not used based on the exponential / custom buckets schema,
   246→// but check fields where differences may cause unintended behaviour even if they are not
   247→// supposed to be used according to the schema.
   248→func (h *Histogram) Equals(h2 *Histogram) bool {
   249→	if h2 == nil {
   250→		return h == nil
   251→	}
   252→
   253→	if h.Schema != h2.Schema || h.Count != h2.Count ||
   254→		math.Float64bits(h.Sum) != math.Float64bits(h2.Sum) {
   255→		return false
   256→	}
   257→
   258→	if h.UsesCustomBuckets() {
   259→		if !CustomBucketBoundsMatch(h.CustomValues, h2.CustomValues) {
   260→			return false
   261→		}
   262→	}
   263→
   264→	if h.ZeroThreshold != h2.ZeroThreshold || h.ZeroCount != h2.ZeroCount {
   265→		return false
   266→	}
   267→
   268→	if !spansMatch(h.NegativeSpans, h2.NegativeSpans) {
   269→		return false
   270→	}
   271→	if !slices.Equal(h.NegativeBuckets, h2.NegativeBuckets) {
   272→		return false
   273→	}
   274→
   275→	if !spansMatch(h.PositiveSpans, h2.PositiveSpans) {
   276→		return false
   277→	}
   278→	if !slices.Equal(h.PositiveBuckets, h2.PositiveBuckets) {
   279→		return false
   280→	}
   281→
   282→	return true
   283→}
